500	    if (typeof payload.conclusionText === "string") {
501	      return titleFromText(payload.conclusionText);
502	    }
503	    if (typeof payload.title === "string") return titleFromText(payload.title);
504	  } catch {
505	    return null;
506	  }
507	  return null;
508	}
