668	    for (const [sourceId, metadata] of dbMetadata) {
669	      const existing = merged.get(sourceId);
670	      merged.set(sourceId, {
671	        conclusionText: metadata.conclusionText ?? existing?.conclusionText ?? null,
672	        conclusionTitle: metadata.conclusionTitle ?? existing?.conclusionTitle ?? null,
673	        publicUrl: metadata.publicUrl ?? existing?.publicUrl ?? null,
674	        sourceVisibility: metadata.sourceVisibility ?? existing?.sourceVisibility ?? null,
675	      });
676	    }
677	    const normalized = normalizeOpinion(opinion, merged);
678	    return {
679	      ...normalized,
680	      reconciliation: reconciliations.get(opinion.id) ?? normalized.reconciliation,
681	    };
682	  });
683	}
