721	export function passThroughHeaders(req: Request): Headers {
722	  const headers = new Headers();
723	  const userAgent = req.headers.get("user-agent");
724	  const contentType = req.headers.get("content-type");
725	  const ip = clientIpFor(req);
726	
727	  if (userAgent) headers.set("user-agent", userAgent);
728	  if (contentType) headers.set("content-type", contentType);
729	  if (ip !== "unknown") headers.set("x-forwarded-for", ip);
730	  headers.set("x-request-id", req.headers.get("x-request-id") || randomUUID());
731	
732	  return headers;
733	}
