775	  if (!upstream.ok) return proxyResponse(upstream);
776	  return new Response(upstream.body, {
777	    status: upstream.status,
778	    statusText: upstream.statusText,
779	    headers: proxiedSseHeaders(upstream),
780	  });
781	}
782	
783	export async function proxyToCurrents(
784	  req: Request,
785	  path: string,
786	  options: {
787	    method?: "GET" | "POST";
788	    body?: BodyInit | null;
789	    headers?: Headers;
790	    sse?: boolean;
791	  } = {},
792	): Promise<Response> {
793	  const sourceUrl = new URL(req.url);
794	  const init: StreamingRequestInit = {
795	    method: options.method ?? req.method,
796	    headers: options.headers ?? passThroughHeaders(req),
797	    cache: "no-store",
798	    redirect: "manual",
799	    signal: req.signal,
800	  };
801	
802	  if (options.body !== undefined) {
803	    init.body = options.body;
804	    if (options.body) init.duplex = "half";
805	  }
806	
807	  try {
808	    const upstream = await fetch(currentsBackendUrl(path, sourceUrl.search), init);
809	    return options.sse ? proxySseResponse(upstream) : proxyResponse(upstream);
810	  } catch (error) {
811	    return upstreamUnavailable(error);
812	  }
813	}
