604	function formatContradictionDetail(summary: ContradictionSummary): string {
605	  const parts: string[] = [];
606	  if (summary.maxSeverity > 0) {
607	    parts.push(`max severity ${(summary.maxSeverity * 100).toFixed(0)}%`);
608	  }
609	  if (summary.newestAt) {
610	    parts.push(`newest ${formatRelativeShort(summary.newestAt)}`);
611	  }
612	  return parts.join(" · ");
613	}
