615	function formatRelativeShort(date: Date): string {
616	  const ms = Date.now() - date.getTime();
617	  if (ms < 60_000) return "just now";
618	  const minutes = Math.floor(ms / 60_000);
619	  if (minutes < 60) return `${minutes}m ago`;
620	  const hours = Math.floor(minutes / 60);
621	  if (hours < 48) return `${hours}h ago`;
622	  const days = Math.floor(hours / 24);
623	  return `${days}d ago`;
624	}
