989	/** Small positive int → Roman numerals, for display accents only. */
990	function toRoman(n: number): string {
991	  if (!n || n < 1) return "";
992	  const table: [number, string][] = [
993	    [10, "X"],
994	    [9, "IX"],
995	    [5, "V"],
996	    [4, "IV"],
997	    [1, "I"],
998	  ];
999	  let out = "";
1000	  let rem = n;
1001	  for (const [v, s] of table) {
1002	    while (rem >= v) {
1003	      out += s;
1004	      rem -= v;
1005	    }
1006	  }
1007	  return out;
1008	}
