69	  const submitDisabledReason = pending
70	    ? "Searching…"
71	    : tooShort
72	    ? "Type at least 3 characters"
73	    : "";
74	
75	  const submit = useCallback(
76	    async (raw: string) => {
77	      const trimmed = raw.trim();
78	      if (trimmed.length < 3) {
79	        setResponse(null);
80	        setError(
