405	            className="mono"
406	            style={{
407	              color: "var(--amber-dim)",
408	              fontSize: "0.6rem",
409	              letterSpacing: "0.22em",
410	              margin: "0 0 0.4rem",
411	              textTransform: "uppercase",
412	            }}
413	          >
414	            Closest open question
415	          </p>
416	          <a
417	            href={response.closestOpenQuestion.href}
418	            style={{
419	              color: "var(--amber)",
420	              fontFamily: "'Cinzel', serif",
421	              fontSize: "1.05rem",
422	              textDecoration: "none",
423	            }}
424	          >
425	            {response.closestOpenQuestion.title}
426	          </a>
427	        </>
428	      ) : (
429	        <p style={{ color: "var(--parchment-dim)", margin: 0 }}>
430	          No published material currently matches this query.
431	        </p>
432	      )}
433	    </div>
434	  );
435	}
436	
437	function SuggestedRephrasings({ titles }: { titles: string[] }) {
438	  return (
439	    <div
440	      data-testid="public-ask-rephrasings"
441	      style={{
442	        border: "1px dashed var(--stroke)",
443	        marginBottom: "1.4rem",
444	        padding: "0.8rem 1rem",
445	      }}
446	    >
447	      <p
448	        className="mono"
449	        style={{
450	          color: "var(--amber-dim)",
451	          fontSize: "0.6rem",
452	          letterSpacing: "0.22em",
453	          margin: "0 0 0.4rem",
454	          textTransform: "uppercase",
455	        }}
456	      >
457	        Did you mean
458	      </p>
459	      <ul style={{ listStyle: "none", margin: 0, padding: 0, display: "flex", gap: "0.6rem", flexWrap: "wrap" }}>
460	        {titles.map((title) => (
461	          <li key={title} style={{ color: "var(--parchment-dim)", fontStyle: "italic" }}>
462	            {title}
463	          </li>
464	        ))}
465	      </ul>
466	    </div>
467	  );
468	}
469	
470	function ResultRow({ item, active }: { item: PublicAskResult; active: boolean }) {
471	  return (
472	    <li
473	      data-testid="public-ask-result-row"
474	      data-active={active ? "true" : undefined}
475	      style={{
476	        background: active ? "rgba(205, 151, 67, 0.08)" : "transparent",
477	        border: "1px solid rgba(232, 225, 211, 0.14)",
478	        borderRadius: 4,
479	        marginBottom: "0.65rem",
480	        padding: "0.85rem",
481	      }}
482	    >
483	      <a
484	        href={item.href}
485	        style={{
486	          color: "var(--amber)",
487	          fontFamily: "'Cinzel', serif",
488	          fontSize: "1.05rem",
489	          lineHeight: 1.25,
490	          textDecoration: "none",
491	        }}
492	      >
493	        {item.title}
494	      </a>
495	      <div
496	        style={{
497	          alignItems: "center",
498	          color: "var(--parchment-dim)",
499	          display: "flex",
500	          flexWrap: "wrap",
501	          gap: "0.55rem",
502	          fontSize: "0.62rem",
503	          letterSpacing: "0.16em",
504	          marginTop: "0.45rem",
505	          textTransform: "uppercase",
506	        }}
507	        className="mono"
508	      >
509	        {item.methodology ? (
510	          <span data-testid="public-ask-methodology-pill" style={pillStyle("var(--gold-dim, var(--amber-dim))")}>
511	            METHOD · {item.methodology}
512	          </span>
513	        ) : null}
514	        {typeof item.confidence === "number" ? (
515	          <span data-testid="public-ask-confidence-pill" style={pillStyle("var(--amber-dim)")}>
516	            CONFIDENCE · {Math.round(item.confidence * 100)}%
517	          </span>
518	        ) : null}
519	        {item.topicHint ? (
520	          <span style={{ color: "var(--parchment-dim)" }}>{item.topicHint}</span>
521	        ) : null}
522	      </div>
523	      <p
524	        style={{
525	          color: "var(--parchment)",
526	          fontFamily: "'EB Garamond', serif",
527	          fontSize: "0.97rem",
528	          lineHeight: 1.5,
529	          margin: "0.55rem 0 0",
530	        }}
531	      >
532	        {item.snippet}
533	      </p>
534	    </li>
535	  );
536	}
537	
538	function pillStyle(color: string): React.CSSProperties {
539	  return {
540	    border: `1px solid ${color}`,
541	    borderRadius: 999,
542	    color,
543	    padding: "0.18rem 0.55rem",
544	  };
545	}
