  conclusion: "CONCLUSIONS",
  article: "ARTICLES",
  opinion: "OPINIONS · CURRENTS",
  open_question: "OPEN QUESTIONS",
};

const SUBMIT_DEBOUNCE_MS = 150;

export default function PublicAskBox({
  mode = "compact",
  initialQuery = "",
  autoFocus = false,
}: {
  mode?: Mode;
  initialQuery?: string;
  autoFocus?: boolean;
}) {
