50	type StreamingRequestInit = RequestInit & { duplex?: "half" };
51	type NextFetchOptions = {
52	  revalidate?: number | false;
53	  tags?: string[];
54	};
55	
56	export interface ForecastsFetchOptions {
57	  cache?: RequestCache;
58	  next?: NextFetchOptions;
59	  signal?: AbortSignal;
60	  timeoutMs?: number;
61	}
62	
63	type NextRequestInit = RequestInit & { next?: NextFetchOptions };
64	
65	function serializeParam(value: string | Date | number | boolean): string {
66	  if (value instanceof Date) return value.toISOString();
67	  return String(value);
68	}
69	
70	type SearchParamValue = string | Date | number | boolean | null | undefined;
71	
72	function searchParamsFor(params: object): URLSearchParams {
73	  const search = new URLSearchParams();
74	  for (const [key, value] of Object.entries(params) as [string, SearchParamValue][]) {
75	    if (value === undefined || value === null || value === "") continue;
76	    search.set(key, serializeParam(value));
77	  }
78	  return search;
79	}
80	
81	function normalizePath(path: string): string {
82	  return path.startsWith("/") ? path : `/${path}`;
83	}
84	
85	function hasPathBoundary(path: string, prefix: string): boolean {
86	  return path === prefix || path.startsWith(`${prefix}/`);
87	}
88	
89	export function isPublicForecastsPath(path: string): boolean {
90	  const normalizedPath = normalizePath(path);
91	  if (normalizedPath === "/v1/operator" || normalizedPath.includes("/v1/operator/")) {
92	    return false;
93	  }
94	  return (
95	    hasPathBoundary(normalizedPath, "/v1/forecasts") ||
96	    hasPathBoundary(normalizedPath, "/v1/markets") ||
97	    hasPathBoundary(normalizedPath, "/v1/portfolio")
98	  );
99	}
100	
101	export function forecastsBackendUrl(path: string, search?: string | URLSearchParams): string {
102	  const normalizedPath = normalizePath(path);
103	  if (!isPublicForecastsPath(normalizedPath)) {
104	    throw new Error(`public forecasts proxy refused upstream path: ${normalizedPath}`);
105	  }
106	
107	  const url = new URL(`${FORECASTS_BACKEND}${normalizedPath}`);
108	  if (search instanceof URLSearchParams) {
109	    url.search = search.toString();
110	  } else if (search) {
111	    url.search = search.startsWith("?") ? search.slice(1) : search;
112	  }
113	  return url.toString();
114	}
115	
116	function timeoutFor(signal: AbortSignal, timeoutMs: number) {
117	  const controller = new AbortController();
118	  let timedOut = false;
119	  let timeoutId: ReturnType<typeof setTimeout> | null = null;
120	
121	  const abortFromRequest = () => controller.abort(signal.reason);
122	  if (signal.aborted) {
123	    abortFromRequest();
124	  } else {
125	    signal.addEventListener("abort", abortFromRequest, { once: true });
126	    if (Number.isFinite(timeoutMs) && timeoutMs > 0) {
127	      timeoutId = setTimeout(() => {
128	        timedOut = true;
129	        controller.abort(new Error("forecasts upstream timeout"));
130	      }, timeoutMs);
131	    }
132	  }
133	
134	  return {
135	    signal: controller.signal,
136	    didTimeout: () => timedOut,
137	    cleanup: () => {
138	      if (timeoutId !== null) clearTimeout(timeoutId);
139	      signal.removeEventListener("abort", abortFromRequest);
140	    },
141	  };
142	}
143	
144	async function fetchJson<T>(
145	  path: string,
146	  search?: URLSearchParams,
147	  options: ForecastsFetchOptions = {},
148	): Promise<T> {
